const lotId = String($('Find buyers for a lot').all()[0].json['Produce lot ID'] || '').trim();
if (!lotId) {
  throw new Error('Please provide a Produce lot ID.');
}
const rows = $('Read produce_lots').all().map(i => i.json);
const lot = rows.find(r => String(r.id).trim() === lotId);
if (!lot) {
  throw new Error('Produce lot ID not found: ' + lotId);
}
return [{ json: lot }];

const lot = $('Select lot').all()[0].json;
const buyers = $('Read buyers').all().map(i => i.json);

const lotCommodity = String(lot.commodity || '').toLowerCase().trim();
const lotQty = parseFloat(lot.quantity);
const lotLocTokens = String(lot.location || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
const lotQuality = String(lot.quality_notes || '').toLowerCase();

const qualityKeywords = ['dry', 'low moisture', 'grade 1', 'bagged', 'fumigated'];
const trustMap = { preferred: 1, verified: 0.7, unverified: 0.3 };

const scored = [];
for (const b of buyers) {
  const trust = String(b.trust_status || '').toLowerCase().trim();
  if (trust === 'blocked') continue; // blocked buyers are never offered for outreach
  const interests = String(b.commodity_interests || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
  if (lotCommodity && interests.length && !interests.includes(lotCommodity)) continue; // hard commodity filter

  const commodity_fit = 1;

  const min = parseFloat(b.min_quantity);
  const max = parseFloat(b.max_quantity);
  let quantity_fit;
  if (isNaN(lotQty)) quantity_fit = 0.3;
  else if (!isNaN(min) && !isNaN(max) && lotQty >= min && lotQty <= max) quantity_fit = 1;
  else if (!isNaN(min) && lotQty < min && lotQty >= min * 0.75) quantity_fit = 0.5;
  else if (!isNaN(max) && lotQty > max && lotQty <= max * 1.25) quantity_fit = 0.5;
  else quantity_fit = 0.2;

  const prefs = String(b.preferred_locations || '').toLowerCase().split(',').map(s => s.trim()).filter(Boolean);
  let location_fit;
  if (prefs.includes('nationwide')) location_fit = 1;
  else if (lotLocTokens.some(t => prefs.includes(t))) location_fit = 1;
  else if (prefs.includes('kaduna')) location_fit = 0.7; // same state, not exact LGA
  else location_fit = 0.3;

  const req = String(b.quality_requirements || '').toLowerCase();
  let quality_fit;
  if (req.includes('any')) quality_fit = 1;
  else {
    const required = qualityKeywords.filter(k => req.includes(k));
    if (required.length === 0) quality_fit = 0.6;
    else {
      const met = required.filter(k => lotQuality.includes(k));
      quality_fit = met.length === required.length ? 1 : (met.length > 0 ? 0.6 : 0.3);
    }
  }

  const trust_score = trustMap[trust] != null ? trustMap[trust] : 0.3;
  const recent_activity_score = 0.5; // placeholder: no last_contacted_at tracked yet (added from Phase 5 deal records)

  const match_score = Math.round(
    commodity_fit * 30 + quantity_fit * 20 + location_fit * 15 + quality_fit * 15 + trust_score * 10 + recent_activity_score * 10
  );

  const risk_flags = [];
  if (trust === 'unverified') risk_flags.push('Buyer unverified - confirm identity before outreach');
  const pay = String(b.payment_terms || '').toLowerCase();
  if (/send goods first|cash on delivery|negotiable|unclear/.test(pay)) risk_flags.push('Payment terms need review: ' + b.payment_terms);
  if (quantity_fit < 1) risk_flags.push('Lot quantity outside buyer preferred range (' + (b.min_quantity || '?') + '-' + (b.max_quantity || '?') + ')');
  if (quality_fit < 0.6) risk_flags.push('Lot quality may not meet requirement: ' + (b.quality_requirements || ''));
  if (location_fit < 1) risk_flags.push('Location not an exact match to buyer preferred areas');

  scored.push({
    buyer_id: b.id,
    name: b.name,
    contact_name: b.contact_name,
    email: b.email,
    trust_status: trust,
    payment_terms: b.payment_terms,
    preferred_locations: b.preferred_locations,
    quality_requirements: b.quality_requirements,
    notes: b.notes,
    min_quantity: b.min_quantity,
    max_quantity: b.max_quantity,
    sub_scores: { commodity_fit, quantity_fit, location_fit, quality_fit, trust_score, recent_activity_score },
    match_score,
    risk_flags
  });
}

scored.sort((a, b) => b.match_score - a.match_score);
const top = scored.slice(0, 3);

const parts = [];
parts.push('You are helping the Kaduna Maize Farmers Cooperative explain why specific buyers were matched to a maize produce lot, and draft a short outreach email to each.');
parts.push('The cooperative aggregates maize from its smallholder member farmers and contacts buyers itself. Write each email in the first person AS the Kaduna Maize Farmers Cooperative, reaching out on behalf of its member farmers - NOT as a third party writing for the cooperative.');
parts.push('Use ONLY the data provided. Do NOT invent buyer details, prices, or guarantees. The outreach is an inquiry only - it must NOT promise a sale, a price, or delivery, and is subject to manager approval and final agreement.');
parts.push('');
parts.push('PRODUCE LOT:');
parts.push('Commodity: ' + lot.commodity);
parts.push('Quantity: ' + lot.quantity + ' ' + lot.unit);
parts.push('Location: ' + lot.location);
parts.push('Availability date: ' + (lot.availability_date || 'not stated'));
parts.push('Asking price: ' + (lot.asking_price || 'not stated') + ' ' + (lot.asking_price_unit || 'per bag'));
parts.push('Quality notes: ' + (lot.quality_notes || 'not stated'));
parts.push('');
parts.push('MATCHED BUYERS (ranked; match_score is out of 100 from a fixed rule-based formula, NOT your judgement):');
top.forEach((m, i) => {
  parts.push((i + 1) + '. ' + m.name + ' (buyer_id: ' + m.buyer_id + ')');
  parts.push('   match_score: ' + m.match_score + ' | trust: ' + m.trust_status + ' | wants qty ' + (m.min_quantity || '?') + '-' + (m.max_quantity || '?'));
  parts.push('   factor fits (0-1): commodity ' + m.sub_scores.commodity_fit + ', quantity ' + m.sub_scores.quantity_fit + ', location ' + m.sub_scores.location_fit + ', quality ' + m.sub_scores.quality_fit + ', trust ' + m.sub_scores.trust_score);
  parts.push('   buyer wants (verbatim) -> preferred_locations: ' + (m.preferred_locations || 'n/a') + ' | quality_requirements: ' + (m.quality_requirements || 'n/a') + ' | payment_terms: ' + (m.payment_terms || 'n/a') + ' | notes: ' + (m.notes || 'n/a'));
  parts.push('   risk_flags: ' + (m.risk_flags.length ? m.risk_flags.join('; ') : 'none'));
});
parts.push('');
parts.push('For EACH buyer return: a 1-2 sentence plain-English explanation that references the concrete factors (quantity, location, quality, trust) - not the raw formula - and a short professional outreach email body (3-5 sentences) that opens by naming the cooperative (Kaduna Maize Farmers Cooperative), introduces the available maize lot, and asks if they are interested, with NO price commitment.');
parts.push('Use the verbatim buyer requirements above to describe how well this lot aligns with what each buyer actually wants (location, quality, payment terms). But you MUST NOT recompute or change the match_score - it is fixed and authoritative - and you MUST NOT claim the lot satisfies a requirement where a risk_flag shows a gap (e.g. unverified buyer, quantity outside range, quality shortfall, non-exact location). Where a risk_flag exists, acknowledge it honestly rather than overclaiming alignment.');
parts.push('Return ONLY a JSON array, no markdown fences, in the same ranked order:');
parts.push('[ { "buyer_id": "...", "explanation": "...", "outreach_draft": "..." } ]');

return [{ json: {
  prompt: parts.join('\n'),
  lot_id: lot.id,
  lot_commodity: lot.commodity,
  lot_quantity: lot.quantity,
  lot_unit: lot.unit,
  lot_location: lot.location,
  top_matches: top,
  top_count: top.length
}}];

const item = $input.all()[0].json;
const score = $('Score buyers').all()[0].json;
const top = score.top_matches || [];
const ts = $now.toISO();

let explanations = [];
try {
  const text = (item.text || item.output || '').replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
  explanations = JSON.parse(text);
  if (!Array.isArray(explanations)) explanations = [];
} catch (e) {
  explanations = [];
}

function findExp(buyerId) {
  return explanations.find(e => String(e.buyer_id) === String(buyerId)) || null;
}

const out = top.map((m, idx) => {
  const exp = findExp(m.buyer_id);
  const explanation = (exp && exp.explanation)
    ? exp.explanation
    : ('Scored ' + m.match_score + '/100 on commodity, quantity (' + score.lot_quantity + ' ' + score.lot_unit + '), location (' + score.lot_location + ') and ' + m.trust_status + ' trust status.');
  const outreach = (exp && exp.outreach_draft)
    ? exp.outreach_draft
    : ('Dear ' + (m.contact_name || m.name) + ', the Kaduna Maize Farmers Cooperative has a maize lot of ' + score.lot_quantity + ' ' + score.lot_unit + ' available in ' + score.lot_location + ' on behalf of our member farmers. Please let us know if you would be interested in discussing supply. This message is an inquiry only and is subject to confirmation.');
  const isTop = idx === 0;
  return { json: {
    id: 'match_' + ts + '_' + m.buyer_id,
    produce_lot_id: score.lot_id,
    buyer_id: m.buyer_id,
    match_score: m.match_score,
    match_reason: explanation,
    risk_flags: m.risk_flags.join('; '),
    status: isTop ? 'pending_approval' : 'draft',
    created_at: ts,
    buyer_name: m.name,
    buyer_contact: m.contact_name,
    buyer_email: m.email,
    trust_status: m.trust_status,
    outreach_draft: outreach,
    is_top: isTop ? 'TRUE' : 'FALSE'
  }};
});

if (out.length === 0) {
  throw new Error('No eligible buyers matched this lot (after commodity and blocked-buyer filtering).');
}

return out;

const matches = $('Parse matches').all().map(i => i.json);
const top = matches.find(m => m.is_top === 'TRUE') || matches[0];
if (!top) {
  throw new Error('No matches available to create an approval request.');
}
const ts = $now.toISO();

const reason = 'Top match: ' + top.buyer_name + ' (score ' + top.match_score + '/100, trust ' + top.trust_status + '). Risk flags: ' + (top.risk_flags || 'none');
const matches_html = matches.map((m, i) => '<li>' + (i + 1) + '. <b>' + m.buyer_name + '</b> - score ' + m.match_score + '/100, trust: ' + m.trust_status + (m.risk_flags ? ' - &#9888; ' + m.risk_flags : '') + '</li>').join('');

return [{ json: {
  id: 'appr_' + ts,
  approval_type: 'buyer_outreach',
  related_entity_id: top.id,
  requested_by: 'system',
  approved_by: '',
  decision: 'pending',
  original_content: top.outreach_draft,
  final_content: '',
  reason: reason,
  decided_at: '',
  matches_html: matches_html
}}];
